  ('dietitian-moex-02437', 'dietitian', 'dietitian-moex-105-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '關於衛生福利部公告之素食飲食指標，下列建議何者錯誤？', '["全穀至少占全穀根莖類的1/2", "每天要有全穀根莖類食物和豆類食品的搭配組合", "多攝食富含維生素C的蔬果，以改善鐵質吸收率", "每天蔬菜應包含至少一份深色蔬菜、一份菇類與一份藻類食物"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:59+00:00", "source_pdf_sha1": "4bd965fce91e", "answer_pdf_sha1": "31a367c7f7c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02438', 'dietitian', 'dietitian-moex-105-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '臺灣國民小學販售之每份飲品或點心，鈉含量應在多少毫克（mg）以下？', '["300", "350", "400", "450"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:59+00:00", "source_pdf_sha1": "4bd965fce91e", "answer_pdf_sha1": "31a367c7f7c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02439', 'dietitian', 'dietitian-moex-105-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列何者不是醫療院所營造友善哺乳環境的要求？', '["鼓勵母嬰同室", "辦理「母嬰親善醫療院所認證」", "嬰幼兒配方食品，只能贈送，不得陳列", "禁止嬰幼兒配方食品、奶瓶及奶嘴之促銷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:59+00:00", "source_pdf_sha1": "4bd965fce91e", "answer_pdf_sha1": "31a367c7f7c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02440', 'dietitian', 'dietitian-moex-105-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某11歲女孩，平均每天的鐵質攝取量為12毫克，根據我國目前的「國人膳食營養素參考攝取量」（DRIs）， 該女孩每天攝取的鐵質是否足夠？11歲女孩每日鐵質的攝取量應為多少毫克？', '["足夠，7", "足夠，10", "不足夠，15", "不足夠，20"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:59+00:00", "source_pdf_sha1": "4bd965fce91e", "answer_pdf_sha1": "31a367c7f7c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
