  ('dietitian-moex-02442', 'dietitian', 'dietitian-moex-105-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '關於學校午餐菜單設計，下列敘述何者與教育部之建議不符？', '["避免提供甜品、冷飲，若要提供以低糖之全穀根莖類為宜（如：綠豆薏仁湯、地瓜湯、紅豆湯等）， 且供應頻率1週不超過1次", "稀釋發酵乳、豆花、愛玉、布丁、茶飲、非100%蔬果汁不符合「校園飲品及點心販售範圍」之規定， 不建議設計", "各式丸類、蝦捲、香腸、火腿、熱狗、重組雞塊等魚肉類半成品，不建議設計", "魚類容易發生食物中毒，不建議設計"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:59+00:00", "source_pdf_sha1": "4bd965fce91e", "answer_pdf_sha1": "31a367c7f7c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
